const payload = $json.body || $json;
const issue = String(payload.issue || payload.message || payload.description || "").trim();
const email = String(payload.email || payload.customer_email || payload.requester_email || payload.user_email || "").trim();
const issueText = issue.toLowerCase();
const selectedType = String(payload.issue_type || payload.category || "general").toLowerCase();
const issueTypeLabels = {
  login: "Login Issue",
  payment: "Payment Failure",
  billing: "Payment Failure",
  technical: "Technical / Bug Issue",
  bug: "Technical / Bug Issue",
  general: "General Inquiry"
};
const issue_type_label = String(payload.issue_type_label || issueTypeLabels[selectedType] || "General Inquiry");
const user_priority = String(payload.user_priority || payload.priority || "low").toLowerCase();
const company_name = String(payload.company_name || payload.company || payload.companyName || payload.selected_company || "Selected Company").trim();
const company_id = String(payload.company_id || payload.companyId || payload.company_slug || company_name).trim();
const slugify = (value) => String(value || "selected_company")
  .trim()
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, "_")
  .replace(/^_+|_+$/g, "") || "selected_company";
const company_slug = String(payload.company_slug || slugify(company_name));
const ticket_table = String(payload.ticket_table || payload.table_name || `${company_slug}_tickets`);

let intent = "General Inquiry";
let ai_priority = "low";
let matched_signal = "Selected category: General Inquiry";
let classification_summary = "The ticket was submitted as a general inquiry, so DeskPilot routed it for general support review.";
let classifier_confidence = "Low";

if (selectedType === "login" || issueText.includes("login")) {
  intent = "Login Issue";
  ai_priority = "high";
  matched_signal = selectedType === "login" ? "Selected category: Login Issue" : "Keyword match: login";
  classification_summary = "DeskPilot detected an account-access problem that can block the user from using the selected company's service.";
  classifier_confidence = "High";
} else if (selectedType === "payment" || selectedType === "billing" || issueText.includes("payment") || issueText.includes("refund") || issueText.includes("invoice") || issueText.includes("billing")) {
  intent = "Payment Issue";
  ai_priority = "high";
  matched_signal = selectedType === "payment" || selectedType === "billing" ? "Selected category: Payment Failure" : "Keyword match: payment/refund/invoice/billing";
  classification_summary = "DeskPilot detected a billing or transaction issue that should be handled by the selected company's billing queue quickly.";
  classifier_confidence = "High";
} else if (selectedType === "technical" || selectedType === "bug" || issueText.includes("bug") || issueText.includes("crash") || issueText.includes("error") || issueText.includes("technical")) {
  intent = "Bug Report";
  ai_priority = "medium";
  matched_signal = selectedType === "technical" || selectedType === "bug" ? "Selected category: Technical / Bug Issue" : "Keyword match: bug/crash/error";
  classification_summary = "DeskPilot detected a product defect, technical issue, or stability problem that should be reviewed by technical support.";
  classifier_confidence = "Medium";
}

return {
  ...$json,
  ...payload,
  email,
  issue,
  issue_type: selectedType,
  issue_type_label,
  user_priority,
  company_id,
  company_name,
  company_slug,
  ticket_table,
  ai_intent: intent,
  ai_priority,
  matched_signal,
  classification_summary,
  classifier_confidence
};

const escapeHtml = (value) => String(value ?? "")
  .replace(/&/g, "&amp;")
  .replace(/</g, "&lt;")
  .replace(/>/g, "&gt;")
  .replace(/"/g, "&quot;")
  .replace(/'/g, "&#39;");

const formatDate = (date) => new Intl.DateTimeFormat("en-IN", {
  dateStyle: "medium",
  timeStyle: "short",
  timeZone: "Asia/Kolkata"
}).format(date);

const user_priority = String($json.user_priority || "low").toLowerCase();
let resolved_priority = user_priority;
let priority_reason = "DeskPilot accepted the priority selected on the ticket form.";

if ($json.ai_priority === "high") {
  resolved_priority = "high";
  priority_reason = "The AI classifier detected a high-impact issue and upgraded the final priority to high.";
} else if ($json.ai_priority === "medium" && user_priority === "low") {
  resolved_priority = "medium";
  priority_reason = "The AI classifier detected a technical failure pattern and raised the ticket from low to medium.";
} else if (user_priority === "high") {
  priority_reason = "The user selected high priority, so DeskPilot preserved high handling urgency.";
}

let assigned_team = "General Support";
let sla_hours = 72;
let routing_reason = "No specialized category was detected, so the ticket was routed to the selected company's general support queue.";
let impact_statement = "The selected company's support team will review the request, confirm the problem type, and route further if needed.";
let response_plan = "A support specialist will review the ticket, ask for any missing details, and provide next steps.";

if ($json.ai_intent === "Login Issue") {
  assigned_team = "Auth Support";
  sla_hours = 24;
  routing_reason = "Login and account-access issues are routed to Auth Support because they own authentication, credentials, and sign-in recovery.";
  impact_statement = "The user may be blocked from accessing the selected company's service until the login issue is resolved.";
  response_plan = "Auth Support will check account status, credential flow, recent login failures, and recovery options.";
} else if ($json.ai_intent === "Payment Issue") {
  assigned_team = "Billing Support";
  sla_hours = 12;
  routing_reason = "Payment, refund, invoice, and billing issues are routed to Billing Support because they own transaction investigation and account charges.";
  impact_statement = "The request may affect billing accuracy, payment completion, or customer trust, so it receives accelerated handling.";
  response_plan = "Billing Support will review transaction status, account billing records, failed payment details, and refund eligibility.";
} else if ($json.ai_intent === "Bug Report") {
  assigned_team = "Tech Team";
  sla_hours = 48;
  routing_reason = "Bug, crash, and error reports are routed to the Tech Team because they own product defects and stability investigation.";
  impact_statement = "The issue may affect product reliability or prevent a workflow from completing as expected.";
  response_plan = "The Tech Team will review reproduction details, affected feature area, logs if available, and possible workaround steps.";
}

const now = new Date();
const sla_deadline = new Date(now.getTime() + sla_hours * 60 * 60 * 1000);
const escalation = resolved_priority === "high" || sla_hours <= 24;
const priority_label = resolved_priority.charAt(0).toUpperCase() + resolved_priority.slice(1);
const user_priority_label = user_priority.charAt(0).toUpperCase() + user_priority.slice(1);
const ai_priority_label = String($json.ai_priority || "low").charAt(0).toUpperCase() + String($json.ai_priority || "low").slice(1);
const priority_style = {
  high: { bg: "#fff1f0", border: "#ffccc7", text: "#a8071a" },
  medium: { bg: "#fff7e6", border: "#ffd591", text: "#ad6800" },
  low: { bg: "#f6ffed", border: "#b7eb8f", text: "#237804" }
}[resolved_priority] || { bg: "#eef2f7", border: "#d9e1ec", text: "#46556d" };

const companyName = String($json.company_name || "Selected Company");
const tableName = String($json.ticket_table || "company_ticket_table");
const companySlug = String($json.company_slug || companyName || "company");
const companyPrefix = (companySlug.replace(/[^a-z0-9]/gi, "").toUpperCase().slice(0, 4) || "DP");
const randomPart = Math.floor(100000 + Math.random() * 900000).toString();
const timePart = now.getTime().toString(36).toUpperCase();
const ticket_id = companyPrefix + "-" + timePart + "-" + randomPart;
const database_issue = "[DeskPilot Ticket ID: " + ticket_id + "] " + String($json.issue || "");

return {
  ...$json,
  ticket_id,
  database_issue,
  priority: resolved_priority,
  priority_label,
  user_priority_label,
  ai_priority_label,
  priority_reason,
  priority_badge_bg: priority_style.bg,
  priority_badge_border: priority_style.border,
  priority_badge_text: priority_style.text,
  assigned_team,
  support_queue: companyName + " / " + assigned_team,
  sla_hours,
  sla_deadline: sla_deadline.toISOString(),
  sla_deadline_display: formatDate(sla_deadline),
  submitted_at: now.toISOString(),
  submitted_at_display: formatDate(now),
  customer_timezone: "Asia/Kolkata",
  routing_reason,
  impact_statement,
  response_plan,
  escalation,
  escalation_status: escalation ? "Escalation monitoring enabled" : "Standard monitoring",
  escalation_reason: escalation
    ? "High-priority or short-SLA tickets are flagged for closer monitoring by the assigned support queue."
    : "The current SLA window is within standard support handling, so no immediate escalation is required.",
  issue_html: escapeHtml($json.issue),
  company_routing_note: "This ticket is isolated to " + companyName + " and stored only in the MySQL table " + tableName + ".",
  automation_summary: "Webhook received the ticket, AI classified the issue, Routing & SLA Engine selected the company queue and SLA, MySQL stored the record in the company-specific table, and SMTP sent this confirmation."
};

